import{_ as i}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{l as s,o as l,c as n,a as e,p as c,i as a,e as d}from"./chunks/vendor-mermaid.BXjKBAcr.js";const C=JSON.parse('{"title":"Customs & Excise Duty in Nepal","description":"A practical guide to customs procedures, excise duty compliance, and HS code classification for importers and manufacturers in Nepal.","frontmatter":{"title":"Customs & Excise Duty in Nepal","description":"A practical guide to customs procedures, excise duty compliance, and HS code classification for importers and manufacturers in Nepal.","sidebar":false,"head":[["meta",{"property":"og:image","content":"https://arthaadvisory.com.np/og_image_test.jpg"}],["meta",{"property":"og:title","content":"Customs & Excise Duty in Nepal | Artha Advisory"}],["meta",{"property":"og:description","content":"A practical guide to customs procedures, excise duty compliance, and HS code classification for importers and manufacturers in Nepal."}],["meta",{"name":"description","content":"A practical guide to customs procedures, excise duty compliance, and HS code classification for importers and manufacturers in Nepal."}]]},"headers":[],"relativePath":"resources/guides/customs-duty-nepal.md","filePath":"resources/guides/customs-duty-nepal.md"}'),u={name:"resources/guides/customs-duty-nepal.md"};function m(p,t,g,h,f,y){const r=s("ReadTime"),o=s("CallToAction");return l(),n("div",null,[t[0]||(t[0]=e("h1",{id:"customs-duty-rates-in-nepal-fy-2081-82",tabindex:"-1"},[c("Customs Duty Rates in Nepal (FY 2081/82) "),e("a",{class:"header-anchor",href:"#customs-duty-rates-in-nepal-fy-2081-82","aria-label":'Permalink to "Customs Duty Rates in Nepal (FY 2081/82)"'},"​")],-1)),t[1]||(t[1]=e("p",null,[e("em",null,"Know the landed cost of your imports before they ship.")],-1)),a(r),t[2]||(t[2]=d('<p>Importing goods into Nepal attracts primarily three types of taxes at the customs point:</p><ol><li><strong>Customs Duty</strong>: Based on HS Code.</li><li><strong>Excise Duty</strong>: On luxury or health-hazard goods.</li><li><strong>VAT</strong>: Flat 13% on (Customs Value + Duty + Excise).</li></ol><hr><h2 id="🚗-vehicles-electric-petroleum" tabindex="-1">🚗 Vehicles (Electric &amp; Petroleum) <a class="header-anchor" href="#🚗-vehicles-electric-petroleum" aria-label="Permalink to &quot;🚗 Vehicles (Electric &amp; Petroleum)&quot;">​</a></h2><h3 id="electric-vehicles-evs-jeep-car-van" tabindex="-1">Electric Vehicles (EVs) - Jeep/Car/Van <a class="header-anchor" href="#electric-vehicles-evs-jeep-car-van" aria-label="Permalink to &quot;Electric Vehicles (EVs) - Jeep/Car/Van&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Kilowatt (kW)</th><th style="text-align:left;">Customs Duty</th><th style="text-align:left;">Excise Duty</th></tr></thead><tbody><tr><td style="text-align:left;">Up to 50 kW</td><td style="text-align:left;">10%</td><td style="text-align:left;">0%</td></tr><tr><td style="text-align:left;">50-100 kW</td><td style="text-align:left;">15%</td><td style="text-align:left;">10%</td></tr><tr><td style="text-align:left;">100-200 kW</td><td style="text-align:left;">20%</td><td style="text-align:left;">20%</td></tr><tr><td style="text-align:left;">200-300 kW</td><td style="text-align:left;">40%</td><td style="text-align:left;">45%</td></tr><tr><td style="text-align:left;">Above 300 kW</td><td style="text-align:left;">60%</td><td style="text-align:left;">60%</td></tr></tbody></table><h3 id="petroleum-vehicles" tabindex="-1">Petroleum Vehicles <a class="header-anchor" href="#petroleum-vehicles" aria-label="Permalink to &quot;Petroleum Vehicles&quot;">​</a></h3><ul><li><strong>Motorcycles (&gt;250cc)</strong>: 80% Customs + 60% Excise.</li><li><strong>Cars (&gt;1000cc)</strong>: 80% Customs + 60% Excise (Base).</li></ul><hr><h2 id="📱-electronics-gadgets" tabindex="-1">📱 Electronics &amp; Gadgets <a class="header-anchor" href="#📱-electronics-gadgets" aria-label="Permalink to &quot;📱 Electronics &amp; Gadgets&quot;">​</a></h2><ul><li><strong>Mobile Phones</strong>: <ul><li>Smartphone: 2.5% Excise + 13% VAT.</li><li>MDMS Registration fee applies for non-official imports.</li></ul></li><li><strong>Laptops/Computers</strong>: 1% Customs Duty (IT Hardware).</li><li><strong>Televisions</strong>: 15% Customs + 13% VAT.</li></ul><hr><h2 id="🪙-gold-silver" tabindex="-1">🪙 Gold &amp; Silver <a class="header-anchor" href="#🪙-gold-silver" aria-label="Permalink to &quot;🪙 Gold &amp; Silver&quot;">​</a></h2><ul><li><strong>Gold (Raw)</strong>: NPR 20,000 per 10 grams.</li><li><strong>Silver</strong>: NPR 107 per 10 grams.</li></ul><blockquote><p><strong>Limit:</strong> Individuals traveling from abroad can bring up to <strong>50 grams</strong> of gold jewelry (tax-free) and an additional <strong>100 grams</strong> by paying full duty. Raw gold bars are strictly prohibited for individuals.</p></blockquote><hr><h2 id="👗-textiles-garments" tabindex="-1">👗 Textiles &amp; Garments <a class="header-anchor" href="#👗-textiles-garments" aria-label="Permalink to &quot;👗 Textiles &amp; Garments&quot;">​</a></h2><ul><li><strong>Readymade Garments</strong>: 20% Customs.</li><li><strong>Synthetic Fabric</strong>: 15% Customs.</li><li><strong>Cotton Yarn</strong>: 5% Customs.</li></ul><hr><h2 id="⚠️-restricted-imports" tabindex="-1">⚠️ Restricted Imports <a class="header-anchor" href="#⚠️-restricted-imports" aria-label="Permalink to &quot;⚠️ Restricted Imports&quot;">​</a></h2><p>Some items are banned or require special permits:</p><ol><li><strong>Energy Drinks</strong> (Total Ban).</li><li><strong>Used/Refurbished Goods</strong> (Ban on import for trading).</li><li><strong>Drones</strong> (Requires permit from Ministry of Home Affairs).</li></ol>',22)),a(o,{title:"Importing Commercial Goods?",text:"Get a correct HS Code classification to avoid fines at the border.",buttonText:"Contact Customs Expert"})])}const v=i(u,[["render",m]]);export{C as __pageData,v as default};
